Here is a Python function to check if a year is a leap year:
python
def is_leap_year(year):
    if year % 4 != 0:
        return False
    elif year % 100 != 0:
        return True
    else:
        return year % 400 == 0

# Example usage:
print(is_leap_year(1900))  # Output: False
print(is_leap_year(2000))  # Output: True
